 1→import { Badge as MantineBadge, type BadgeProps as MantineBadgeProps } from '@mantine/core'
 2→
 3→type Variant = 'default' | 'accent' | 'outline' | 'secondary'
 4→
 5→export interface BadgeProps extends React.HTMLAttributes<HTMLDivElement> {
 6→  variant?: Variant
 7→}
 8→
 9→const variantMap: Record<Variant, Pick<MantineBadgeProps, 'variant' | 'color'>> = {
10→  default: { variant: 'filled', color: 'brand' },
11→  accent: { variant: 'filled', color: 'accent' },
12→  outline: { variant: 'outline', color: 'brand' },
13→  secondary: { variant: 'light', color: 'brand' },
14→}
15→
16→function Badge({ variant = 'default', className, children, ...props }: BadgeProps) {
17→  const mapped = variantMap[variant]
18→  return (
19→    <MantineBadge
20→      variant={mapped.variant}
21→      color={mapped.color}
22→      className={className}
23→      {...props}
24→    >
25→      {children}
26→    </MantineBadge>
27→  )
28→}
29→
30→export { Badge }
