  1→import type { SearchField, SearchFieldUnit, SearchInstitution, SearchOutputField, Theme } from './types'
  2→import { lookupEnumLabel } from '@/lib/enumLabels'
  3→
  4→// Field names rendered first in the sidebar, in order. Unknown fields follow alphabetically by label.
  5→export const PREFERRED_ORDER = ['name', 'city', 'state']
  6→
  7→export function sortFields(fields: SearchField[]): SearchField[] {
  8→  return [...fields].sort((a, b) => {
  9→    const ai = PREFERRED_ORDER.indexOf(a.name)
 10→    const bi = PREFERRED_ORDER.indexOf(b.name)
 11→    if (ai !== -1 && bi !== -1) return ai - bi
 12→    if (ai !== -1) return -1
 13→    if (bi !== -1) return 1
 14→    return a.label.localeCompare(b.label)
 15→  })
 16→}
 17→
 18→// Ordered list of themes for sidebar rendering. Only themes with fields are shown.
 19→export const THEME_ORDER: Theme[] = [
 20→  'CORE',
 21→  'LOCATION',
 22→  'ACADEMICS',
 23→  'COST',
 24→  'OUTCOMES',
 25→  'RANKING',
 26→  'ADMISSIONS',
 27→  'ATHLETICS',
 28→  'FIELDS_OF_STUDY',
 29→  'CULTURAL_ENVIRONMENT',
 30→  'WEATHER',
 31→]
 32→
 33→export const THEME_LABELS: Record<Theme, string> = {
 34→  CORE: 'Core',
 35→  LOCATION: 'Location',
 36→  ACADEMICS: 'Academics',
 37→  COST: 'Cost & Financial Aid',
 38→  OUTCOMES: 'Outcomes',
 39→  RANKING: 'Rankings',
 40→  ADMISSIONS: 'Admissions',
 41→  ATHLETICS: 'Athletics',
 42→  FIELDS_OF_STUDY: 'Fields of Study',
 43→  CULTURAL_ENVIRONMENT: 'Cultural Environment',
 44→  WEATHER: 'Weather & Climate',
 45→  PHYSICAL_ENVIRONMENT: 'Physical Environment',
 46→  DEMOGRAPHICS: 'Demographics',
 47→  REPUTATION: 'Reputation',
 48→  SAFETY: 'Safety',
 49→  STUDENT_LIFE: 'Student Life',
 50→  METADATA: 'Metadata',
 51→  OTHER: 'Other',
 52→}
 53→
 54→export interface ThemeGroup {
 55→  theme: Theme
 56→  label: string
 57→  fields: SearchField[]
 58→}
 59→
 60→export function fieldsByTheme(fields: SearchField[]): ThemeGroup[] {
 61→  // Group fields by theme
 62→  const grouped = new Map<Theme, SearchField[]>()
 63→  for (const f of fields) {
 64→    const existing = grouped.get(f.theme)
 65→    if (existing) {
 66→      existing.push(f)
 67→    } else {
 68→      grouped.set(f.theme, [f])
 69→    }
 70→  }
 71→
 72→  // Sort fields within each group alphabetically by label
 73→  for (const group of grouped.values()) {
 74→    group.sort((a, b) => a.label.localeCompare(b.label))
 75→  }
 76→
 77→  // Build ordered result: known themes first, then any unknown themes
 78→  const result: ThemeGroup[] = []
 79→  for (const theme of THEME_ORDER) {
 80→    const group = grouped.get(theme)
 81→    if (group && group.length > 0) {
 82→      result.push({ theme, label: THEME_LABELS[theme], fields: group })
 83→      grouped.delete(theme)
 84→    }
 85→  }
 86→  // Append any remaining themes not in THEME_ORDER
 87→  for (const [theme, group] of grouped) {
 88→    if (group.length > 0) {
 89→      result.push({ theme, label: THEME_LABELS[theme] ?? String(theme), fields: group })
 90→    }
 91→  }
 92→
 93→  return result
 94→}
 95→
 96→const MILES_TO_KM = 1.60934
 97→
 98→export function buildFilterInputs(
 99→  filters: Record<string, unknown>,
100→): Array<{ field: string; value: unknown }> {
101→  return Object.entries(filters).map(([field, value]) => {
102→    if (
103→      typeof value === 'object' &&
104→      value !== null &&
105→      'latitude' in value &&
106→      'longitude' in value &&
107→      'radiusMiles' in value
108→    ) {
109→      const v = value as { latitude: number; longitude: number; radiusMiles: number }
110→      return {
111→        field,
112→        value: {
113→          kind: 'radius',
114→          radius: { lat: v.latitude, lng: v.longitude, radius_km: v.radiusMiles * MILES_TO_KM },
115→        },
116→      }
117→    }
118→    return { field, value }
119→  })
120→}
121→
122→export function serializeFilterValue(value: unknown): string {
123→  if (typeof value === 'object' && value !== null) {
124→    if ('query' in value) return String((value as { query: string }).query)
125→    if ('value' in value) return String((value as { value: string }).value)
126→    if ('values' in value) return (value as { values: string[] }).values.join(',')
127→    if ('latitude' in value && 'longitude' in value && 'radiusMiles' in value) {
128→      const g = value as { latitude: number; longitude: number; radiusMiles: number }
129→      return `${g.latitude},${g.longitude},${g.radiusMiles}`
130→    }
131→    if ('max' in value && !('min' in value))
132→      return String((value as { max: number }).max)
133→    if ('min' in value && !('max' in value))
134→      return String((value as { min: number }).min)
135→    if ('min' in value && 'max' in value) {
136→      const r = value as { min: number; max: number }
137→      return `${r.min},${r.max}`
138→    }
139→  }
140→  return String(value)
141→}
142→
143→export function parseUrlToFilters(
144→  params: URLSearchParams,
145→  fields: SearchField[],
146→): Record<string, unknown> {
147→  const filters: Record<string, unknown> = {}
148→  const fieldMap = new Map(fields.map((f) => [f.name, f]))
149→
150→  // Handle legacy ?q= param — maps to the "name" field
151→  const q = params.get('q')
152→  if (q && !params.has('name')) {
153→    filters.name = { query: q }
154→  }
155→
156→  for (const [key, raw] of params.entries()) {
157→    if (key === 'q') continue
158→    const field = fieldMap.get(key)
159→    if (!field) continue
160→
161→    if (field.__typename === 'TextSearchField') {
162→      filters[key] = { query: raw }
163→    } else if (field.__typename === 'BinarySearchField') {
164→      filters[key] = { value: raw }
165→    } else if (field.__typename === 'ChoiceSearchField') {
166→      if (field.maxSelections === 1) {
167→        filters[key] = { value: raw }
168→      } else {
169→        filters[key] = { values: raw.split(',').filter(Boolean) }
170→      }
171→    } else if (field.__typename === 'NumericalSearchField') {
172→      const num = Number(raw)
173→      if (!isNaN(num)) {
174→        filters[key] = { value: num }
175→      }
176→    } else if (field.__typename === 'GeoSearchField') {
177→      const parts = raw.split(',')
178→      if (parts.length === 3) {
179→        const [lat, lng, r] = parts.map(Number)
180→        if (!isNaN(lat) && !isNaN(lng) && !isNaN(r)) {
181→          filters[key] = { latitude: lat, longitude: lng, radiusMiles: r }
182→        }
183→      }
184→    } else if (field.__typename === 'NumericalRangeSearchField') {
185→      if (raw.includes(',')) {
186→        const [minStr, maxStr] = raw.split(',')
187→        const minVal = Number(minStr)
188→        const maxVal = Number(maxStr)
189→        if (!isNaN(minVal) && !isNaN(maxVal)) {
190→          filters[key] = { min: minVal, max: maxVal }
191→        }
192→      } else {
193→        const num = Number(raw)
194→        if (!isNaN(num)) {
195→          filters[key] = { max: num }
196→        }
197→      }
198→    }
199→  }
200→
201→  return filters
202→}
203→
204→export interface OutputFieldThemeGroup {
205→  theme: Theme
206→  label: string
207→  fields: SearchOutputField[]
208→}
209→
210→export function outputFieldsByTheme(fields: SearchOutputField[]): OutputFieldThemeGroup[] {
211→  const grouped = new Map<Theme, SearchOutputField[]>()
212→  for (const f of fields) {
213→    const existing = grouped.get(f.theme)
214→    if (existing) {
215→      existing.push(f)
216→    } else {
217→      grouped.set(f.theme, [f])
218→    }
219→  }
220→
221→  const result: OutputFieldThemeGroup[] = []
222→  for (const theme of THEME_ORDER) {
223→    const group = grouped.get(theme)
224→    if (group && group.length > 0) {
225→      result.push({ theme, label: THEME_LABELS[theme], fields: group })
226→      grouped.delete(theme)
227→    }
228→  }
229→  for (const [theme, group] of grouped) {
230→    if (group.length > 0) {
231→      result.push({ theme, label: THEME_LABELS[theme] ?? String(theme), fields: group })
232→    }
233→  }
234→
235→  return result
236→}
