238→/**
239→ * Navigates a dot-path (e.g. "academics.enrollment") into a SearchInstitution
240→ * and returns the leaf value. Returns undefined if any segment is missing.
241→ */
242→export function getFieldValue(
243→  inst: SearchInstitution,
244→  outputKey: string | null | undefined,
245→): unknown {
246→  if (!outputKey) return undefined
247→  const parts = outputKey.split('.')
248→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
249→  let current: any = inst
250→  for (const part of parts) {
251→    if (current == null || typeof current !== 'object') return undefined
252→    current = current[part]
253→  }
254→  return current ?? undefined
255→}
256→
257→/**
258→ * Parse a blend URL param like "rank_us_news_national:40,rank_forbes:30" into a record.
259→ */
260→export function parseBlendParam(raw: string | null): Record<string, number> {
261→  if (!raw) return {}
262→  const result: Record<string, number> = {}
263→  for (const pair of raw.split(',')) {
264→    const [field, weightStr] = pair.split(':')
265→    if (field && weightStr) {
266→      const weight = Number(weightStr)
267→      if (!isNaN(weight) && weight > 0) {
268→        result[field] = weight
269→      }
270→    }
271→  }
272→  return result
273→}
274→
275→/**
276→ * Serialize blend weights to a URL param string.
277→ * Only includes non-zero weights.
278→ */
279→export function serializeBlendWeights(weights: Record<string, number>): string {
280→  return Object.entries(weights)
281→    .filter(([, w]) => w > 0)
282→    .map(([field, weight]) => `${field}:${weight}`)
283→    .join(',')
284→}
285→
286→export function formatCellValue(
287→  value: unknown,
288→  unit?: SearchFieldUnit | null,
289→  fieldName?: string,
290→): string {
291→  if (value === null || value === undefined || value === '') return '—'
292→  if (fieldName) {
293→    const label = lookupEnumLabel(fieldName, String(value))
294→    if (label !== null) return label
295→  }
296→  const num = Number(value)
297→  if (unit === 'DOLLARS' && !isNaN(num)) {
298→    return `$${Math.round(num).toLocaleString()}`
299→  }
300→  if (unit === 'PERCENTAGE' && !isNaN(num)) {
301→    return `${(num * 100).toFixed(1)}%`
302→  }
303→  if (unit === 'MILES' && !isNaN(num)) {
304→    return `${num.toLocaleString()} mi`
305→  }
306→  return String(value)
307→}
