import { Badge as MantineBadge, type BadgeProps as MantineBadgeProps } from '@mantine/core'

type Variant = 'default' | 'accent' | 'outline' | 'secondary'

export interface BadgeProps extends React.HTMLAttributes<HTMLDivElement> {
  variant?: Variant
}

const variantMap: Record<Variant, Pick<MantineBadgeProps, 'variant' | 'color'>> = {
  default: { variant: 'filled', color: 'brand' },
  accent: { variant: 'filled', color: 'accent' },
  outline: { variant: 'outline', color: 'brand' },
  secondary: { variant: 'light', color: 'brand' },
}

function Badge({ variant = 'default', className, children, ...props }: BadgeProps) {
  const mapped = variantMap[variant]
  return (
    <MantineBadge
      variant={mapped.variant}
      color={mapped.color}
      className={className}
      {...props}
    >
      {children}
    </MantineBadge>
  )
}

export { Badge }

