}

/**
 * Look up a human-readable label for an enum code.
 * Returns null if the field name is not an enum field or the code is unknown.
 * Callers should fall back to the raw value when null is returned.
 */
export function lookupEnumLabel(
  fieldName: string,
  code: string | null | undefined,
): string | null {
  if (code == null) return null
  return ENUM_LABELS[fieldName]?.[code] ?? null
}

