import { Badge, CloseButton, Group } from '@mantine/core'
import { Button } from '@/components/ui/button'
import { lookupEnumLabel } from '@/lib/enumLabels'
import type { SearchField } from './types'
import { formatCellValue } from './helpers'

export interface ActiveFilterPillsProps {
  filters: Record<string, unknown>
  fields: SearchField[]
  onRemove: (fieldName: string) => void
  onClearAll: () => void
}

function formatFilterValue(fieldName: string, value: unknown, field: SearchField): string {
  if (typeof value !== 'object' || value === null) return String(value)

  if ('query' in value) return String((value as { query: string }).query)

  if ('values' in value) {
    const vals = (value as { values: string[] }).values
    if (vals.length === 1) {
      const label =
        field.options?.find((o) => o.value === vals[0])?.displayName ??
        lookupEnumLabel(fieldName, vals[0]) ??
        vals[0]
      return label
    }
    return `${vals.length} selected`
  }

  if ('value' in value) {
    const raw = String((value as { value: string }).value)
    return (
      field.options?.find((o) => o.value === raw)?.displayName ??
      lookupEnumLabel(fieldName, raw) ??
      formatCellValue(raw, field.unit, fieldName)
    )
  }

  if ('min' in value || 'max' in value) {
    const v = value as { min?: number; max?: number }
    const fmt = (n: number) => formatCellValue(n, field.unit)
    if (v.min != null && v.max != null) return `${fmt(v.min)} – ${fmt(v.max)}`
    if (v.min != null) return `${fmt(v.min)}+`
    if (v.max != null) return `up to ${fmt(v.max)}`
  }

  if ('latitude' in value && 'radiusMiles' in value) {
    const g = value as { radiusMiles: number }
    return `within ${g.radiusMiles} mi`
  }

  return String(value)
}

function ActiveFilterPills({ filters, fields, onRemove, onClearAll }: ActiveFilterPillsProps) {
  const activeKeys = Object.keys(filters)
  if (activeKeys.length === 0) return null

  const fieldMap = new Map(fields.map((f) => [f.name, f]))

  return (
    <Group gap="xs" wrap="wrap" mb="sm">
      {activeKeys.map((key) => {
        const field = fieldMap.get(key)
        if (!field) return null
        const label = field.label
        const valueText = formatFilterValue(key, filters[key], field)
        return (
          <Badge
            key={key}
            variant="light"
            color="brand"
            size="lg"
            pr={3}
            rightSection={
              <CloseButton
                size="xs"
                variant="transparent"
                aria-label={`Remove ${label} filter`}
                onClick={() => onRemove(key)}
              />
            }
          >
            {label}: {valueText}
          </Badge>
        )
      })}
      {activeKeys.length >= 2 && (
        <Button variant="subtle" size="xs" onClick={onClearAll}>
          Clear all
        </Button>
      )}
    </Group>
  )
}

export { ActiveFilterPills }

