import { describe, it, expect, vi } from 'vitest'
import { screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { renderWithMantine } from '@/test/render'
import { ActiveFilterPills } from './ActiveFilterPills'
import type { SearchField } from './types'

const baseField: SearchField = {
  __typename: 'TextSearchField',
  name: 'name',
  label: 'Name',
  description: '',
  theme: 'CORE',
  visibility: 'VISIBLE',
  searchability: 'SEARCHABLE',
  exportable: true,
}

const choiceField: SearchField = {
  ...baseField,
  __typename: 'ChoiceSearchField',
  name: 'control',
  label: 'Control',
  options: [
    { value: '1', displayName: 'Public' },
    { value: '2', displayName: 'Private nonprofit' },
  ],
  maxSelections: 1,
}

const rangeField: SearchField = {
  ...baseField,
  __typename: 'NumericalRangeSearchField',
  name: 'tuition',
  label: 'Tuition',
  unit: 'DOLLARS',
}

const multiChoiceField: SearchField = {
  ...baseField,
  __typename: 'ChoiceSearchField',
  name: 'platforms',
  label: 'Platforms',
  options: [
    { value: 'a', displayName: 'Common App' },
    { value: 'b', displayName: 'Coalition' },
    { value: 'c', displayName: 'Direct' },
  ],
  maxSelections: null,
}

const fields: SearchField[] = [baseField, choiceField, rangeField, multiChoiceField]

describe('ActiveFilterPills', () => {
  it('renders nothing when filters are empty', () => {
    const { container } = renderWithMantine(
      <ActiveFilterPills filters={{}} fields={fields} onRemove={vi.fn()} onClearAll={vi.fn()} />,
    )
    expect(container.innerHTML).toBe('')
  })

  it('renders a pill with label and value for a text filter', () => {
    renderWithMantine(
      <ActiveFilterPills
        filters={{ name: { query: 'Harvard' } }}
        fields={fields}
        onRemove={vi.fn()}
        onClearAll={vi.fn()}
      />,
    )
    expect(screen.getByText(/Name.*Harvard/i)).toBeInTheDocument()
  })

  it('renders displayName for a choice filter', () => {
    renderWithMantine(
      <ActiveFilterPills
        filters={{ control: { value: '1' } }}
        fields={fields}
        onRemove={vi.fn()}
        onClearAll={vi.fn()}
      />,
    )
    expect(screen.getByText(/Control.*Public/i)).toBeInTheDocument()
  })

  it('renders count for multi-select with multiple values', () => {
    renderWithMantine(
      <ActiveFilterPills
        filters={{ platforms: { values: ['a', 'b', 'c'] } }}
        fields={fields}
        onRemove={vi.fn()}
        onClearAll={vi.fn()}
      />,
    )
    expect(screen.getByText(/Platforms.*3 selected/i)).toBeInTheDocument()
  })

  it('renders displayName for multi-select with single value', () => {
    renderWithMantine(
      <ActiveFilterPills
        filters={{ platforms: { values: ['a'] } }}
        fields={fields}
        onRemove={vi.fn()}
        onClearAll={vi.fn()}
      />,
    )
    expect(screen.getByText(/Platforms.*Common App/i)).toBeInTheDocument()
  })

  it('renders range values with units', () => {
    renderWithMantine(
      <ActiveFilterPills
        filters={{ tuition: { min: 10000, max: 50000 } }}
        fields={fields}
        onRemove={vi.fn()}
        onClearAll={vi.fn()}
      />,
    )
    expect(screen.getByText(/Tuition/)).toBeInTheDocument()
    expect(screen.getByText(/\$10,000/)).toBeInTheDocument()
  })

  it('shows "Clear all" when 2+ filters are active', () => {
    renderWithMantine(
      <ActiveFilterPills
        filters={{ name: { query: 'MIT' }, control: { value: '1' } }}
        fields={fields}
        onRemove={vi.fn()}
        onClearAll={vi.fn()}
      />,
    )
    expect(screen.getByText('Clear all')).toBeInTheDocument()
  })

  it('hides "Clear all" when only 1 filter', () => {
    renderWithMantine(
      <ActiveFilterPills
        filters={{ name: { query: 'MIT' } }}
        fields={fields}
        onRemove={vi.fn()}
        onClearAll={vi.fn()}
      />,
    )
    expect(screen.queryByText('Clear all')).not.toBeInTheDocument()
  })

  it('calls onRemove with field name when close button is clicked', async () => {
    const onRemove = vi.fn()
    renderWithMantine(
      <ActiveFilterPills
        filters={{ name: { query: 'MIT' } }}
        fields={fields}
        onRemove={onRemove}
        onClearAll={vi.fn()}
      />,
    )
    await userEvent.click(screen.getByLabelText('Remove Name filter'))
    expect(onRemove).toHaveBeenCalledWith('name')
  })

  it('calls onClearAll when "Clear all" is clicked', async () => {
    const onClearAll = vi.fn()
    renderWithMantine(
      <ActiveFilterPills
        filters={{ name: { query: 'MIT' }, control: { value: '1' } }}
        fields={fields}
        onRemove={vi.fn()}
        onClearAll={onClearAll}
      />,
    )
    await userEvent.click(screen.getByText('Clear all'))
    expect(onClearAll).toHaveBeenCalled()
  })
})

